import { useEffect } from 'react';
import { useVoucherInitData } from './useVoucherInitData';
import { applyVoucherAccountDefault } from '../utils/voucherAccountDefaults';

/** Zone B report filter — default TK from init-data when session cache empty (`form-init-data.md` § Account defaults). */
export function useReportAccountFilterDefault(
  formName: string,
  sessionAccountCode: string | undefined,
  accountCode: string,
  setAccountCode: (code: string) => void,
  setAccountName: (name: string) => void,
): void {
  const { defaultAccount } = useVoucherInitData(formName);

  useEffect(() => {
    if (sessionAccountCode?.trim()) return;
    applyVoucherAccountDefault(true, accountCode, defaultAccount, setAccountCode, setAccountName);
  }, [sessionAccountCode, accountCode, defaultAccount, setAccountCode, setAccountName]);
}
